export function getCountryByName(name: string): CountryEntry | undefined {
  return COUNTRIES_WITH_STATES.find(c => c.name.toLowerCase() === name.toLowerCase());
}

export function getCountryByCode(code: string): CountryEntry | undefined {
  return COUNTRIES_WITH_STATES.find(c => c.code.toUpperCase() === code.toUpperCase());
}